-- Binômes de formation (académie) + Groupuscules (Detective Bureau).
CREATE TABLE `Partnership` (`id` INTEGER NOT NULL AUTO_INCREMENT, `rookieId` INTEGER NOT NULL, `instructorId` INTEGER NOT NULL, `createdById` INTEGER NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `Partnership_rookieId_idx`(`rookieId`), INDEX `Partnership_instructorId_idx`(`instructorId`), PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4;
CREATE TABLE `PartnershipNote` (`id` INTEGER NOT NULL AUTO_INCREMENT, `partnershipId` INTEGER NOT NULL, `authorId` INTEGER NOT NULL, `body` TEXT NOT NULL, `visibility` VARCHAR(191) NOT NULL DEFAULT 'BOTH', `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `PartnershipNote_partnershipId_idx`(`partnershipId`), PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4;
CREATE TABLE `Faction` (`id` INTEGER NOT NULL AUTO_INCREMENT, `name` VARCHAR(191) NOT NULL, `description` TEXT NOT NULL, `status` VARCHAR(191) NOT NULL DEFAULT 'ACTIVE', `createdById` INTEGER NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, INDEX `Faction_status_idx`(`status`), PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4;
CREATE TABLE `FactionNote` (`id` INTEGER NOT NULL AUTO_INCREMENT, `factionId` INTEGER NOT NULL, `authorId` INTEGER NOT NULL, `body` TEXT NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `FactionNote_factionId_idx`(`factionId`), PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4;
CREATE TABLE `FactionReport` (`factionId` INTEGER NOT NULL, `reportId` INTEGER NOT NULL, `linkedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `FactionReport_reportId_idx`(`reportId`), PRIMARY KEY (`factionId`, `reportId`)) DEFAULT CHARACTER SET utf8mb4;
CREATE TABLE `FactionInvestigation` (`factionId` INTEGER NOT NULL, `investigationId` INTEGER NOT NULL, `linkedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `FactionInvestigation_investigationId_idx`(`investigationId`), PRIMARY KEY (`factionId`, `investigationId`)) DEFAULT CHARACTER SET utf8mb4;
CREATE TABLE `FactionCivilian` (`factionId` INTEGER NOT NULL, `civilianId` INTEGER NOT NULL, `role` VARCHAR(191) NULL, `linkedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `FactionCivilian_civilianId_idx`(`civilianId`), PRIMARY KEY (`factionId`, `civilianId`)) DEFAULT CHARACTER SET utf8mb4;
ALTER TABLE `Partnership` ADD CONSTRAINT `Partnership_rookieId_fkey` FOREIGN KEY (`rookieId`) REFERENCES `User`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `Partnership` ADD CONSTRAINT `Partnership_instructorId_fkey` FOREIGN KEY (`instructorId`) REFERENCES `User`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `Partnership` ADD CONSTRAINT `Partnership_createdById_fkey` FOREIGN KEY (`createdById`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE `PartnershipNote` ADD CONSTRAINT `PartnershipNote_partnershipId_fkey` FOREIGN KEY (`partnershipId`) REFERENCES `Partnership`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `PartnershipNote` ADD CONSTRAINT `PartnershipNote_authorId_fkey` FOREIGN KEY (`authorId`) REFERENCES `User`(`id`) ON UPDATE CASCADE;
ALTER TABLE `Faction` ADD CONSTRAINT `Faction_createdById_fkey` FOREIGN KEY (`createdById`) REFERENCES `User`(`id`) ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE `FactionNote` ADD CONSTRAINT `FactionNote_factionId_fkey` FOREIGN KEY (`factionId`) REFERENCES `Faction`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `FactionNote` ADD CONSTRAINT `FactionNote_authorId_fkey` FOREIGN KEY (`authorId`) REFERENCES `User`(`id`) ON UPDATE CASCADE;
ALTER TABLE `FactionReport` ADD CONSTRAINT `FactionReport_factionId_fkey` FOREIGN KEY (`factionId`) REFERENCES `Faction`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `FactionReport` ADD CONSTRAINT `FactionReport_reportId_fkey` FOREIGN KEY (`reportId`) REFERENCES `Report`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `FactionInvestigation` ADD CONSTRAINT `FactionInvestigation_factionId_fkey` FOREIGN KEY (`factionId`) REFERENCES `Faction`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `FactionInvestigation` ADD CONSTRAINT `FactionInvestigation_investigationId_fkey` FOREIGN KEY (`investigationId`) REFERENCES `Investigation`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `FactionCivilian` ADD CONSTRAINT `FactionCivilian_factionId_fkey` FOREIGN KEY (`factionId`) REFERENCES `Faction`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE `FactionCivilian` ADD CONSTRAINT `FactionCivilian_civilianId_fkey` FOREIGN KEY (`civilianId`) REFERENCES `Civilian`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
